-            dm2[i] = getDouble();
+            for (int j = 0; j < DIM; j++) {
+                int idx = i * DIM + j;
+                fm[idx] = Float.intBitsToFloat(RANDOM.nextInt());
+                fm2[idx] = Float.intBitsToFloat(RANDOM.nextInt());
+                dm[idx] = Double.longBitsToDouble(RANDOM.nextLong());
+                dm2[idx] = Double.longBitsToDouble(RANDOM.nextLong());
